import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

import org.owasp.esapi.ESAPI;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String userInput = request.getParameter("input");

        // Properly encode and sanitize user input using ESAPI
        String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);

        // Output the sanitized user input in the response
        response.getWriter().write("<html><body>User Input: " + sanitizedInput + "</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
